from collections import defaultdict
import json

class SLRParser:
 def __init__(self, productions):
 """
 productions: list of tuples (lhs, rhs) where rhs is a list of symbols
 Example: [('S', ['E']), ('E', ['E', '+', 'T']), ('E', ['T']), ...]
 """
 self.orig_productions = productions
 self.productions = [] # Will include augmented production
 self.non_terminals = set()
 self.terminals = set()
 self.grammar_symbols = set()
 self.first = defaultdict(set)
 self.follow = defaultdict(set)
 self.states = []
 self.goto_table = {}
 self.action_table = {}

 def build_parser(self):
 """Main method to build the complete SLR parsing table"""
 self._preprocess_grammar()
 self._compute_first()
 self._compute_follow()
 self._build_canonical_collection()
 self._build_parsing_table()

 def _preprocess_grammar(self):
 """Augment grammar and identify terminals/non-terminals"""
 # Add augmented production S' -> S
 start_symbol = self.orig_productions[0][0]
 self.productions.append(('S\'', [start_symbol]))

 # Add original productions with index
 for i, (lhs, rhs) in enumerate(self.orig_productions):
 self.productions.append((lhs, rhs))
 self.non_terminals.add(lhs)

 # Identify terminals and non-terminals
 for lhs, rhs in self.orig_productions:
 for symbol in rhs:
 if symbol.islower() or symbol in '+*()id':
 self.terminals.add(symbol)
 elif symbol.isupper() and len(symbol) == 1:
 self.non_terminals.add(symbol)

 self.grammar_symbols = self.terminals | self.non_terminals
 self.terminals.add('$') # End-of-input marker

 def _compute_first(self):
 """Compute FIRST sets for all grammar symbols"""
 # Initialize FIRST sets
 for terminal in self.terminals:
 self.first[terminal] = {terminal}
 for non_term in self.non_terminals:
 self.first[non_term] = set()

 # Iteratively compute FIRST sets
 changed = True
 while changed:
 changed = False
 for lhs, rhs in self.productions:
 # If RHS starts with terminal, add it
 if rhs and rhs[0] in self.terminals:
 if rhs[0] not in self.first[lhs]:
 self.first[lhs].add(rhs[0])
 changed = True
 # If RHS starts with non-terminal, add its FIRST (excluding epsilon)
 elif rhs and rhs[0] in self.non_terminals:
 before_size = len(self.first[lhs])
 self.first[lhs].update(self.first[rhs[0]] - {'ε'})
 if len(self.first[lhs]) > before_size:
 changed = True

 # Handle epsilon in productions
 if not rhs or 'ε' in rhs:
 if 'ε' not in self.first[lhs]:
 self.first[lhs].add('ε')
 changed = True

 def _compute_follow(self):
 """Compute FOLLOW sets for all non-terminals"""
 start_symbol = 'S\''
 self.follow[start_symbol] = {'$'}

 # Initialize non-terminal follows
 for nt in self.non_terminals:
 if nt not in self.follow:
 self.follow[nt] = set()

 changed = True
 while changed:
 changed = False
 for lhs, rhs in self.productions:
 if lhs == 'S\'':
 continue

 # Find all positions where non-terminal appears
 for i, symbol in enumerate(rhs):
 if symbol in self.non_terminals:
 # Case 1: A → αBβ, add FIRST(β) - {ε} to FOLLOW(B)
 if i + 1 < len(rhs):
 next_symbols = rhs[i + 1:]
 first_beta = set()
 for sym in next_symbols:
 first_beta.update(self.first[sym] - {'ε'})
 if 'ε' not in self.first[sym]:
 break
 before = len(self.follow[symbol])
 self.follow[symbol].update(first_beta)
 if len(self.follow[symbol]) > before:
 changed = True

 # Case 2: A → αB or A → αBβ (where β derives ε)
 # Add FOLLOW(A) to FOLLOW(B)
 can_derive_epsilon = True
 if i + 1 >= len(rhs):
 can_derive_epsilon = True
 else:
 for sym in rhs[i + 1:]:
 if 'ε' not in self.first[sym]:
 can_derive_epsilon = False
 break

 if can_derive_epsilon or i + 1 >= len(rhs):
 before = len(self.follow[symbol])
 self.follow[symbol].update(self.follow[lhs])
 if len(self.follow[symbol]) > before:
 changed = True

 def _closure(self, items):
 """Compute closure of a set of LR(0) items"""
 closure_set = set(items)

 changed = True
 while changed:
 changed = False
 new_items = set()
 for (lhs, rhs, dot) in closure_set:
 if dot < len(rhs):
 next_symbol = rhs[dot]
 if next_symbol in self.non_terminals:
 # Add B → •γ for production B → γ
 for prod_lhs, prod_rhs in self.productions:
 if prod_lhs == next_symbol:
 new_item = (prod_lhs, prod_rhs, 0)
 if new_item not in closure_set:
 new_items.add(new_item)
 changed = True
 closure_set.update(new_items)

 return closure_set

 def _goto(self, items, symbol):
 """Compute GOTO(I, X) - move dot past symbol and take closure"""
 new_items = set()

 for (lhs, rhs, dot) in items:
 if dot < len(rhs) and rhs[dot] == symbol:
 new_items.add((lhs, rhs, dot + 1))

 if new_items:
 return self._closure(new_items)
 return set()

 def _build_canonical_collection(self):
 """Build canonical collection of LR(0) item sets"""
 # Initial state: closure of [S' → •S]
 initial_items = [('S\'', self.productions[0][1], 0)]
 initial_closure = self._closure(initial_items)

 self.states = [initial_closure]
 self.goto_table = {i: {} for i in range(len(self.states))}

 # Build all states
 changed = True
 while changed:
 changed = False
 for i, state in enumerate(self.states):
 for symbol in self.grammar_symbols:
 goto_result = self._goto(state, symbol)
 if goto_result and goto_result not in self.states:
 self.states.append(goto_result)
 self.goto_table[len(self.states) - 1] = {}
 changed = True

 def _build_parsing_table(self):
 """Build ACTION and GOTO tables from canonical collection"""
 self.action_table = {i: {} for i in range(len(self.states))}

 for i, state in enumerate(self.states):
 # Check for reduce items (dot at end)
 for (lhs, rhs, dot) in state:
 if dot == len(rhs):
 # This is a reduce item
 if lhs == 'S\'' and len(rhs) == 1 and rhs[0] == self.productions[0][1][0]:
 # Accept action
 self.action_table[i]['$'] = ('accept', None)
 else:
 # Reduce by production
 for terminal in self.follow[lhs]:
 prod_str = lhs + '→' + ''.join(rhs)
 self.action_table[i][terminal] = ('reduce', prod_str)

 # Check for shift items
 for symbol in self.terminals:
 if symbol == '$':
 continue
 goto_result = self._goto(state, symbol)
 if goto_result:
 j = self.states.index(goto_result)
 self.action_table[i][symbol] = ('shift', j)
 self.goto_table[i][symbol] = j

 # GOTO for non-terminals
 for nt in self.non_terminals:
 goto_result = self._goto(state, nt)
 if goto_result:
 j = self.states.index(goto_result)
 self.goto_table[i][nt] = j

 def print_tables(self):
 """Print the ACTION and GOTO tables in readable format"""
 print("=" * 70)
 print("SLR PARSING TABLE")
 print("=" * 70)

 # Print ACTION table
 print("\nACTION Table:")
 print("-" * 50)
 for state, actions in self.action_table.items():
 if actions:
 print(f"State {state}:")
 for symbol, (action_type, value) in sorted(actions.items()):
 if action_type == 'shift':
 print(f" {symbol}: shift {value}")
 elif action_type == 'reduce':
 print(f" {symbol}: reduce by {value}")
 elif action_type == 'accept':
 print(f" {symbol}: accept")

 print("\nGOTO Table:")
 print("-" * 50)
 for state, gotos in self.goto_table.items():
 if gotos:
 non_term_gotos = {k: v for k, v in gotos.items() if k in self.non_terminals}
 if non_term_gotos:
 print(f"State {state}: {non_term_gotos}")

 print("\n" + "=" * 70)
 print("FOLLOW Sets:")
 print("-" * 50)
 for nt, follow_set in sorted(self.follow.items()):
 if nt != 'S\'':
 print(f"FOLLOW({nt}) = {follow_set}")


