def main():
 # Grammar:
 # E → E + T | T
 # T → T * F | F
 # F → ( E ) | id
 productions = [
 ('E', ['E', '+', 'T']),
 ('E', ['T']),
 ('T', ['T', '*', 'F']),
 ('T', ['F']),
 ('F', ['(', 'E', ')']),
 ('F', ['id'])
 ]

 parser = SLRParser(productions)
 parser.build_parser()
 parser.print_tables()

 # Print canonical collection
 print("\n" + "=" * 70)
 print("CANONICAL COLLECTION OF LR(0) ITEM SETS")
 print("=" * 70)
 for i, state in enumerate(parser.states):
 print(f"\nState I{i}:")
 for (lhs, rhs, dot) in sorted(state):
 rhs_with_dot = rhs[:dot] + ['•'] + rhs[dot:]
 print(f" {lhs} → {' '.join(rhs_with_dot)}")


if __name__ == "__main__":
 main()

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_PRODUCTIONS 20
#define MAX_SYMBOLS 20
#define MAX_STATES 50
#define MAX_ITEMS 100

// Structure to represent a production
typedef struct {
 char lhs;
 char rhs[10];
 int rhs_len;
} Production;

// Structure for an LR(0) item: A -> alpha . beta
typedef struct {
 char lhs;
 char rhs[10];
 int rhs_len;
 int dot_position;
} LR0Item;

// Structure for a set of items (state)
typedef struct {
 LR0Item items[MAX_ITEMS];
 int item_count;
} ItemSet;

// Global variables
Production productions[MAX_PRODUCTIONS];
int num_productions;

char terminals[MAX_SYMBOLS];
char non_terminals[MAX_SYMBOLS];
int num_terminals, num_non_terminals;

char first_sets[MAX_SYMBOLS][MAX_SYMBOLS];
int first_count[MAX_SYMBOLS];

char follow_sets[MAX_SYMBOLS][MAX_SYMBOLS];
int follow_count[MAX_SYMBOLS];

ItemSet states[MAX_STATES];
int num_states;

// Action table: action[state][terminal] = {type, value}
// type: 0=error, 1=shift, 2=reduce, 3=accept
typedef struct {
 int type; // 0=none, 1=shift, 2=reduce, 3=accept
 int value; // state number for shift, production index for reduce
} Action;

Action action_table[MAX_STATES][MAX_SYMBOLS];
int goto_table[MAX_STATES][MAX_SYMBOLS];

// Find index of a symbol
int find_terminal_index(char c) {
 for (int i = 0; i < num_terminals; i++) {
 if (terminals[i] == c) return i;
 }
 return -1;
}

int find_non_terminal_index(char c) {
 for (int i = 0; i < num_non_terminals; i++) {
 if (non_terminals[i] == c) return i;
 }
 return -1;
}

// Add item to set (avoid duplicates)
bool add_item(ItemSet *set, LR0Item item) {
 for (int i = 0; i < set->item_count; i++) {
 if (set->items[i].lhs == item.lhs &&
 set->items[i].dot_position == item.dot_position &&
 set->items[i].rhs_len == item.rhs_len) {
 bool same = true;
 for (int j = 0; j < item.rhs_len; j++) {
 if (set->items[i].rhs[j] != item.rhs[j]) {
 same = false;
 break;
 }
 }
 if (same) return false;
 }
 }
 set->items[set->item_count++] = item;
 return true;
}

// Check if two item sets are equal
bool item_sets_equal(ItemSet *a, ItemSet *b) {
 if (a->item_count != b->item_count) return false;
 for (int i = 0; i < a->item_count; i++) {
 bool found = false;
 for (int j = 0; j < b->item_count; j++) {
 if (a->items[i].lhs == b->items[j].lhs &&
 a->items[i].dot_position == b->items[j].dot_position &&
 a->items[i].rhs_len == b->items[j].rhs_len) {
 bool same = true;
 for (int k = 0; k < a->items[i].rhs_len; k++) {
 if (a->items[i].rhs[k] != b->items[j].rhs[k]) {
 same = false;
 break;
 }
 }
 if (same) {
 found = true;
 break;
 }
 }
 }
 if (!found) return false;
 }
 return true;
}

// Compute closure of an item set
void closure(ItemSet *result, ItemSet *input) {
 result->item_count = 0;

 // Add all items from input
 for (int i = 0; i < input->item_count; i++) {
 result->items[result->item_count++] = input->items[i];
 }

 bool changed = true;
 while (changed) {
 changed = false;
 for (int i = 0; i < result->item_count; i++) {
 LR0Item item = result->items[i];

 // If dot is not at the end
 if (item.dot_position < item.rhs_len) {
 char next_symbol = item.rhs[item.dot_position];

 // If next symbol is a non-terminal, add its items
 if (find_non_terminal_index(next_symbol) >= 0) {
 for (int p = 0; p < num_productions; p++) {
 if (productions[p].lhs == next_symbol) {
 LR0Item new_item;
 new_item.lhs = productions[p].lhs;
 strncpy(new_item.rhs, productions[p].rhs, 10);
 new_item.rhs_len = productions[p].rhs_len;
 new_item.dot_position = 0;

 if (add_item(result, new_item)) {
 changed = true;
 }
 }
 }
 }
 }
 }
 }
}

// Compute GOTO(I, X)
void compute_goto(ItemSet *result, ItemSet *I, char X) {
 result->item_count = 0;

 // Move dot past X
 for (int i = 0; i < I->item_count; i++) {
 LR0Item item = I->items[i];
 if (item.dot_position < item.rhs_len && 
 item.rhs[item.dot_position] == X) {
 LR0Item new_item = item;
 new_item.dot_position++;
 result->items[result->item_count++] = new_item;
 }
 }

 // Take closure
 if (result->item_count > 0) {
 ItemSet temp;
 closure(&temp, result);
 *result = temp;
 }
}

// Find index of existing state
int find_state_index(ItemSet *target) {
 for (int i = 0; i < num_states; i++) {
 if (item_sets_equal(&states[i], target)) {
 return i;
 }
 }
 return -1;
}

// Build canonical collection of LR(0) items
void build_canonical_collection() {
 num_states = 0;

 // Create initial state I0: closure of [S' -> .S]
 ItemSet I0;
 I0.item_count = 0;
 LR0Item start_item;
 start_item.lhs = 'S';
 start_item.rhs[0] = productions[0].rhs[0]; // Original start symbol
 start_item.rhs_len = 1;
 start_item.dot_position = 0;
 add_item(&I0, start_item);

 ItemSet closure_result;
 closure(&closure_result, &I0);
 states[num_states++] = closure_result;

 // Build all states
 bool changed = true;
 while (changed) {
 changed = false;
 for (int i = 0; i < num_states; i++) {
 // For each grammar symbol
 for (char c = 'A'; c <= 'Z'; c++) {
 if (find_non_terminal_index(c) >= 0 || find_terminal_index(c) >= 0) {
 ItemSet goto_result;
 compute_goto(&goto_result, &states[i], c);

 if (goto_result.item_count > 0) {
 int idx = find_state_index(&goto_result);
 if (idx < 0) {
 states[num_states++] = goto_result;
 changed = true;
 }
 }
 }
 }
 }
 }
}

// Initialize terminals and non-terminals
void init_symbols() {
 // From grammar: E -> E+T | T, T -> T*F | F, F -> (E) | id
 num_terminals = 0;
 terminals[num_terminals++] = 'i'; // 'i' represents 'id'
 terminals[num_terminals++] = '+';
 terminals[num_terminals++] = '*';
 terminals[num_terminals++] = '(';
 terminals[num_terminals++] = ')';
 terminals[num_terminals++] = '$'; // end marker

 num_non_terminals = 0;
 non_terminals[num_non_terminals++] = 'S';
 non_terminals[num_non_terminals++] = 'E';
 non_terminals[num_non_terminals++] = 'T';
 non_terminals[num_non_terminals++] = 'F';

 // Initialize productions (augmented grammar: S' -> E)
 productions[0].lhs = 'S';
 productions[0].rhs[0] = 'E';
 productions[0].rhs_len = 1;

 productions[1].lhs = 'E';
 productions[1].rhs[0] = 'E';
 productions[1].rhs[1] = '+';
 productions[1].rhs[2] = 'T';
 productions[1].rhs_len = 3;

 productions[2].lhs = 'E';
 productions[2].rhs[0] = 'T';
 productions[2].rhs_len = 1;

 productions[3].lhs = 'T';
 productions[3].rhs[0] = 'T';
 productions[3].rhs[1] = '*';
 productions[3].rhs[2] = 'F';
 productions[3].rhs_len = 3;

 productions[4].lhs = 'T';
 productions[4].rhs[0] = 'F';
 productions[4].rhs_len = 1;

 productions[5].lhs = 'F';
 productions[5].rhs[0] = '(';
 productions[5].rhs[1] = 'E';
 productions[5].rhs[2] = ')';
 productions[5].rhs_len = 3;

 productions[6].lhs = 'F';
 productions[6].rhs[0] = 'i';
 productions[6].rhs_len = 1;

 num_productions = 7;
}

// Compute FIRST sets (simplified)
void compute_first() {
 // Initialize
 for (int i = 0; i < MAX_SYMBOLS; i++) {
 first_count[i] = 0;
 }

 // Terminals: FIRST(t) = {t}
 int idx = find_terminal_index('i');
 first_sets[idx][first_count[idx]++] = 'i';
 idx = find_terminal_index('+');
 first_sets[idx][first_count[idx]++] = '+';
 idx = find_terminal_index('*');
 first_sets[idx][first_count[idx]++] = '*';
 idx = find_terminal_index('(');
 first_sets[idx][first_count[idx]++] = '(';
 idx = find_terminal_index(')');
 first_sets[idx][first_count[idx]++] = ')';

 // Non-terminals: iterative computation
 bool changed = true;
 while (changed) {
 changed = false;
 for (int p = 0; p < num_productions; p++) {
 int lhs_idx = find_non_terminal_index(productions[p].lhs);

 // If RHS starts with terminal
 if (productions[p].rhs_len > 0) {
 char first_sym = productions[p].rhs[0];
 int sym_idx = find_terminal_index(first_sym);
 if (sym_idx >= 0) {
 // Add terminal to FIRST(lhs)
 for (int i = 0; i < first_count[sym_idx]; i++) {
 char term = first_sets[sym_idx][i];
 bool exists = false;
 for (int j = 0; j < first_count[lhs_idx]; j++) {
 if (first_sets[lhs_idx][j] == term) {
 exists = true;
 break;
 }
 }
 if (!exists) {
 first_sets[lhs_idx][first_count[lhs_idx]++] = term;
 changed = true;
 }
 }
 }
 }
 }
 }
}

// Compute FOLLOW sets
void compute_follow() {
 // Initialize
 for (int i = 0; i < MAX_SYMBOLS; i++) {
 follow_count[i] = 0;
 }

 // FOLLOW(S) = {$}
 int s_idx = find_non_terminal_index('S');
 follow_sets[s_idx][follow_count[s_idx]++] = '$';

 // Compute others based on grammar rules
 // FOLLOW(E) = {$, +, )}
 int e_idx = find_non_terminal_index('E');
 follow_sets[e_idx][follow_count[e_idx]++] = '$';
 follow_sets[e_idx][follow_count[e_idx]++] = '+';
 follow_sets[e_idx][follow_count[e_idx]++] = ')';

 // FOLLOW(T) = {$, +, *, )}
 int t_idx = find_non_terminal_index('T');
 follow_sets[t_idx][follow_count[t_idx]++] = '$';
 follow_sets[t_idx][follow_count[t_idx]++] = '+';
 follow_sets[t_idx][follow_count[t_idx]++] = '*';
 follow_sets[t_idx][follow_count[t_idx]++] = ')';

 // FOLLOW(F) = {$, +, *, )}
 int f_idx = find_non_terminal_index('F');
 follow_sets[f_idx][follow_count[f_idx]++] = '$';
 follow_sets[f_idx][follow_count[f_idx]++] = '+';
 follow_sets[f_idx][follow_count[f_idx]++] = '*';
 follow_sets[f_idx][follow_count[f_idx]++] = ')';
}

// Build the SLR parsing table
void build_slr_table() {
 // Initialize tables
 for (int i = 0; i < MAX_STATES; i++) {
 for (int j = 0; j < MAX_SYMBOLS; j++) {
 action_table[i][j].type = 0;
 goto_table[i][j] = -1;
 }
 }

 // For each state
 for (int i = 0; i < num_states; i++) {
 ItemSet state = states[i];

 // For each item in the state
 for (int j = 0; j < state.item_count; j++) {
 LR0Item item = state.items[j];

 // Case 1: Dot at end - reduce action
 if (item.dot_position == item.rhs_len) {
 if (item.lhs == 'S' && item.rhs_len == 1 && item.rhs[0] == 'E') {
 // Accept
 int term_idx = find_terminal_index('$');
 if (term_idx >= 0) {
 action_table[i][term_idx].type = 3; // accept
 }
 } else {
 // Reduce by production
 // Find production index
 int prod_idx = -1;
 for (int p = 0; p < num_productions; p++) {
 if (productions[p].lhs == item.lhs &&
 productions[p].rhs_len == item.rhs_len) {
 bool same = true;
 for (int k = 0; k < item.rhs_len; k++) {
 if (productions[p].rhs[k] != item.rhs[k]) {
 same = false;
 break;
 }
 }
 if (same) {
 prod_idx = p;
 break;
 }
 }
 }

 if (prod_idx > 0) { // Not the augmented production
 // Get FOLLOW set for the LHS
 int nt_idx = find_non_terminal_index(item.lhs);
 for (int f = 0; f < follow_count[nt_idx]; f++) {
 char follow_term = follow_sets[nt_idx][f];
 int term_idx = find_terminal_index(follow_term);
 if (term_idx >= 0 && action_table[i][term_idx].type == 0) {
 action_table[i][term_idx].type = 2; // reduce
 action_table[i][term_idx].value = prod_idx;
 }
 }
 }
 }
 }
 // Case 2: Dot before terminal - shift action
 else if (item.dot_position < item.rhs_len) {
 char next_sym = item.rhs[item.dot_position];
 int term_idx = find_terminal_index(next_sym);
 if (term_idx >= 0) {
 // Compute GOTO
 ItemSet goto_result;
 compute_goto(&goto_result, &state, next_sym);

 if (goto_result.item_count > 0) {
 int target_state = find_state_index(&goto_result);
 if (target_state >= 0) {
 action_table[i][term_idx].type = 1; // shift
 action_table[i][term_idx].value = target_state;
 goto_table[i][term_idx] = target_state;
 }
 }
 }
 }
 }
 }
}

// Print the parsing table
void print_parsing_table() {
 printf("\n========================================\n");
 printf("SLR PARSING TABLE\n");
 printf("========================================\n\n");

 printf("ACTION Table:\n");
 printf("----------------------------------------\n");
 printf("%5s", "State");
 for (int j = 0; j < num_terminals; j++) {
 printf("%8c", terminals[j]);
 }
 printf("\n");

 for (int i = 0; i < num_states; i++) {
 printf("%5d", i);
 for (int j = 0; j < num_terminals; j++) {
 if (action_table[i][j].type == 1) {
 printf("%8s%d", "s", action_table[i][j].value);
 } else if (action_table[i][j].type == 2) {
 printf("%8s%d", "r", action_table[i][j].value);
 } else if (action_table[i][j].type == 3) {
 printf("%8s", "acc");
 } else {
 printf("%8s", "");
 }
 }
 printf("\n");
 }

 printf("\nGOTO Table:\n");
 printf("----------------------------------------\n");
 printf("%5s", "State");
 for (int j = 0; j < num_non_terminals; j++) {
 if (non_terminals[j] != 'S') // Skip augmented
 printf("%8c", non_terminals[j]);
 }
 printf("\n");

 for (int i = 0; i < num_states; i++) {
 printf("%5d", i);
 for (int j = 0; j < num_non_terminals; j++) {
 if (non_terminals[j] == 'S') continue;
 int nt_idx = find_non_terminal_index(non_terminals[j]);
 if (goto_table[i][nt_idx] >= 0) {
 printf("%8d", goto_table[i][nt_idx]);
 } else {
 printf("%8s", "");
 }
 }
 printf("\n");
 }
}

// Print item sets
void print_states() {
 printf("\n========================================\n");
 printf("CANONICAL COLLECTION OF LR(0) ITEMS\n");
 printf("========================================\n\n");

 for (int i = 0; i < num_states; i++) {
 printf("State I%d:\n", i);
 for (int j = 0; j < states[i].item_count; j++) {
 LR0Item item = states[i].items[j];
 printf(" %c -> ", item.lhs);
 for (int k = 0; k < item.rhs_len; k++) {
 if (k == item.dot_position) printf(". ");
 printf("%c ", item.rhs[k]);
 }
 if (item.dot_position == item.rhs_len) printf(". ");
 printf("\n");
 }
 printf("\n");
 }
}

